const raw = $input.first().json;
const text = String(raw.query ?? raw.chatInput ?? raw.issue_number ?? raw.input ?? '').trim();
const m = text.match(/#?(\d{3,6})/);
if (!m) {
  return [{ json: { issueNumber: null, response: 'Provide an issue number (e.g. 14361 or #14361).' } }];
}
return [{ json: { issueNumber: parseInt(m[1], 10) } }];

const parsed = $('Parse input').first().json;
if (!parsed.issueNumber) {
  return [{ json: { response: parsed.response } }];
}
const issueNumber = parsed.issueNumber;
const q = `repo:n8n-io/n8n type:pr ${issueNumber} in:body`;
const res = await this.helpers.httpRequestWithAuthentication.call(this, 'githubApi', {
  method: 'GET',
  url: `https://api.github.com/search/issues?q=${encodeURIComponent(q)}&per_page=15`,
  json: true,
});
const items = (res.items || []).filter((x) => x.number);
if (!items.length) {
  return [{ json: { response: `No open PRs found linking to #${issueNumber}. Try searching manually on GitHub.` } }];
}
const md = items.slice(0, 10).map((p) => {
  const url = p.html_url || `https://github.com/n8n-io/n8n/pull/${p.number}`;
  return `• [#${p.number}](${url}) ${p.state || 'open'} — ${p.title}\n  by @${p.user?.login ?? 'unknown'}`;
}).join('\n\n');
return [{ json: { response: `Open PRs potentially linked to #${issueNumber}:\n\n${md}` } }];
